code.pages/global.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100vw;
  height: 100vh;
  background: url(./bg.jpg) no-repeat 50% 50%;
  background-size: cover;
  font-family: "Acid Grotesk";
}

header {
  position: fixed;
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 1em;
}

header .header-items {
  display: flex;
}

header .header-items .header-item,
.logo {
  padding: 1em 2em;
}

a {
  text-decoration: none;
  color: #fff;
  font-weight: 500;
  font-size: 15px;
}

h1 {
  width: 75%;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  text-align: center;
  font-weight: 500;
  font-size: 100px;
  line-height: 90%;
  color: #fff;
}

.slide-in {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100vh;
  background: #001aff;
  transform-origin: bottom;
}

.slide-out {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100vh;
  background: #001aff;
  transform-origin: top;
}

